Vec <pre><code>let mut v = Vec::new();
v.push(1);
v.push(2);

let v = vec![1, 2, 3];  // macro shorthand

// Borrowing
let third: &amp;i32 = &amp;v[2];        // panics if out of bounds
let third: Option&lt;&amp;i32&gt; = v.get(2);  // returns None if out of bounds

// Iteration
for val in &amp;v { }       // immutable borrow
for val in &amp;mut v { }   // mutable borrow
for val in v { }         // takes ownership (v consumed)
</code></pre>

HashMap <pre><code>use std::collections::HashMap;

let mut scores = HashMap::new();
scores.insert("Alice", 100);
scores.insert("Bob", 85);

// Entry API - insert if absent
scores.entry("Charlie").or_insert(0);

// Update existing
let count = scores.entry("Alice").or_insert(0);
*count += 10;

// From iterators
let map: HashMap&lt;_, _&gt; = vec![("a", 1), ("b", 2)].into_iter().collect();
</code></pre>

String Operations <pre><code>let mut s = String::from("hello");
s.push(' ');
s.push_str("world");

let s = format!("{} {}", "hello", "world");

// Iteration over chars (not bytes)
for c in "hello".chars() { }
for b in "hello".bytes() { }

// &amp;String → &amp;str coercion via Deref
fn greet(name: &amp;str) { }
let owned = String::from("Alice");
greet(&amp;owned);  // auto-deref to &amp;str
</code></pre>

Box - Heap Allocation <pre><code>// Recursive type (requires known size)
enum List {
    Cons(i32, Box&lt;List&gt;),
    Nil,
}

// Trait objects
let animal: Box&lt;dyn Animal&gt; = Box::new(Dog { name: "Rex".into() });

// Large data on heap
let big_array = Box::new([0u8; 1_000_000]);
</code></pre>

Rc - Reference Counting <pre><code>use std::rc::Rc;

let a = Rc::new(vec![1, 2, 3]);
let b = Rc::clone(&amp;a);  // increment reference count (cheap)
let c = Rc::clone(&amp;a);

println!("References: {}", Rc::strong_count(&amp;a)); // 3
// Data dropped when last Rc goes out of scope
</code></pre>

RefCell - Interior Mutability <pre><code>use std::cell::RefCell;

let data = RefCell::new(vec![1, 2, 3]);

// Runtime borrow checking
let borrowed = data.borrow();      // immutable borrow
// data.borrow_mut();              // PANIC: already borrowed immutably
drop(borrowed);

data.borrow_mut().push(4);         // OK: no active borrows
</code></pre>

Common Combinations <pre><code>// Multiple owners with mutability (single-threaded)
let shared = Rc::new(RefCell::new(HashMap::new()));

// Multiple owners with mutability (multi-threaded)
let shared = Arc::new(Mutex::new(HashMap::new()));
</code></pre>
